mapper.select:
SELECT i.id, i.name, i.name_zh AS nameZh, i.internal_name AS internalName, AS image, i.category_id AS categoryId, c.name AS categoryName, ( SELECT GROUP_CONCAT(DISTINCT icr.category_id ORDER BY icr.is_primary DESC, icr.sort_order ASC, icr.category_id ASC SEPARATOR ',') FROM item_category_rel icr WHERE icr.item_id = i.id AND icr.deleted = 0 AND icr.status = 1 ) AS relatedCategoryIdsRaw, i.description, i.description_zh AS descriptionZh, i.damage, i.defense, i.knockback AS knockback, i.use_time AS useTime, i.width AS width, i.height AS height, i.buy AS buy, i.sell AS sell, i.tooltip AS tooltip, i.tooltip_zh AS tooltipZh, i.rarity_id AS rarityId, COALESCE(ir.display_name_zh, ir.display_name_en) AS rarity, i.game_period_id AS gamePeriodId, COALESCE(gp.display_name_zh, gp.display_name_en) AS gamePeriod, i.game_model_id AS gameModelId, i.is_stackable AS isStackable, i.stack_size AS stackSize, i.status, i.created_at AS createdAt, i.updated_at AS updatedAt FROM items i LEFT JOIN category c ON c.id = i.category_id AND c.deleted = 0 LEFT JOIN item_rarity ir ON ir.id = i.rarity_id AND ir.deleted = 0 AND ir.status = 1 LEFT JOIN game_period gp ON gp.id = i.game_period_id AND gp.deleted = 0 AND gp.status = 1
i.deleted = 0
AND ( i.name LIKE CONCAT('%', #{search}, '%') OR i.name_zh LIKE CONCAT('%', #{search}, '%') OR i.internal_name LIKE CONCAT('%', #{search}, '%') )
AND ( i.category_id IN
#{categoryIdItem}
OR EXISTS ( SELECT 1 FROM item_category_rel icr_filter WHERE icr_filter.item_id = i.id AND icr_filter.deleted = 0 AND icr_filter.status = 1 AND icr_filter.category_id IN
#{categoryIdItem}
) )
AND ( i.category_id = #{categoryId} OR EXISTS ( SELECT 1 FROM item_category_rel icr_filter WHERE icr_filter.item_id = i.id AND icr_filter.deleted = 0 AND icr_filter.status = 1 AND icr_filter.category_id = #{categoryId} ) )
AND i.rarity_id = #{rarityId}
AND i.game_period_id = #{gamePeriodId}
ORDER BY i.name ASC, i.id ASC
ORDER BY i.name DESC, i.id ASC
ORDER BY i.rarity_id ASC, i.id ASC
ORDER BY i.rarity_id DESC, i.id ASC
ORDER BY i.id ASC

SELECT i.category_id AS categoryId, COUNT(*) AS count FROM items i WHERE i.deleted = 0 AND i.category_id IN
#{categoryIdItem}
GROUP BY i.category_id
